mapper.select:
SELECT *
FROM iot_device_thing_model
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0
LIMIT 1

mapper.update:
UPDATE iot_device_thing_model
SET is_delete = 1,
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0
